import{_ as e,c as p,o as i,a as o}from"./app.50048430.js";const b=JSON.parse('{"title":"\u539F\u59CB\u7C7B\u578B\u5305\u88C5\u5668","description":"","frontmatter":{"title":"\u539F\u59CB\u7C7B\u578B\u5305\u88C5\u5668","date":"2017-06-16T00:00:00.000Z","tags":["JS"]},"headers":[{"level":2,"title":"Number","slug":"number"},{"level":3,"title":"\u9759\u6001\u6210\u5458","slug":"\u9759\u6001\u6210\u5458"},{"level":3,"title":"\u5B9E\u4F8B\u6210\u5458","slug":"\u5B9E\u4F8B\u6210\u5458"},{"level":2,"title":"Boolean","slug":"boolean"},{"level":2,"title":"String","slug":"string"},{"level":3,"title":"\u9759\u6001\u6210\u5458","slug":"\u9759\u6001\u6210\u5458-1"},{"level":3,"title":"\u5B9E\u4F8B\u6210\u5458","slug":"\u5B9E\u4F8B\u6210\u5458-1"}],"relativePath":"js/Wrapper.md","lastUpdated":1661212217000}'),d={name:"js/Wrapper.md"},l=o('<h1 id="\u539F\u59CB\u7C7B\u578B\u5305\u88C5\u5668" tabindex="-1">\u539F\u59CB\u7C7B\u578B\u5305\u88C5\u5668 <a class="header-anchor" href="#\u539F\u59CB\u7C7B\u578B\u5305\u88C5\u5668" aria-hidden="true">#</a></h1><ul><li>new \u5305\u88C5\u5668(\u503C)\uFF1A\u8FD4\u56DE\u4E00\u4E2A\u5BF9\u8C61\u3002</li><li>\u5305\u88C5\u5668(\u503C)\uFF1A\u8FD4\u56DE\u4E00\u4E2A\u539F\u59CB\u7C7B\u578B\u3002</li></ul><h2 id="number" tabindex="-1">Number <a class="header-anchor" href="#number" aria-hidden="true">#</a></h2><p><a href="https://developer.mozilla.org/zh-CN/docs/Web/JavaScript/Reference/Global_Objects/Number" target="_blank" rel="noreferrer">MDN</a></p><h3 id="\u9759\u6001\u6210\u5458" tabindex="-1">\u9759\u6001\u6210\u5458 <a class="header-anchor" href="#\u9759\u6001\u6210\u5458" aria-hidden="true">#</a></h3><ul><li><p><code>isNaN() </code></p><p>\u786E\u5B9A\u4F20\u9012\u7684\u503C\u662F\u5426\u662F NaN\u3002</p></li><li><p><code>isFinite() </code></p><p>\u786E\u5B9A\u4F20\u9012\u7684\u503C\u7C7B\u578B\u53CA\u672C\u8EAB\u662F\u5426\u662F\u6709\u9650\u6570\u3002</p></li><li><p><code>isInteger() </code></p><p>\u786E\u5B9A\u4F20\u9012\u7684\u503C\u7C7B\u578B\u662F\u201Cnumber\u201D\uFF0C\u4E14\u662F\u6574\u6570\u3002</p></li><li><p><code>parseFloat() </code></p><p>\u5C06\u4E00\u4E2A\u6570\u636E\u8F6C\u6362\u4E3A\u5C0F\u6570\u3002</p></li><li><p><code>parseInt() </code></p><p>\u5C06\u4E00\u4E2A\u6570\u636E\u8F6C\u6362\u4E3A\u6574\u6570\uFF0C\u76F4\u63A5\u820D\u53BB\u5C0F\u6570\u90E8\u5206\u3002</p></li></ul><p>parseFloat\u3001parseInt \u8981\u6C42\u53C2\u6570\u662F\u4E00\u4E2A\u5B57\u7B26\u4E32\uFF0C\u5982\u679C\u4E0D\u662F\u5B57\u7B26\u4E32\uFF0C\u5219\u4F1A\u5148\u8F6C\u6362\u4E3A\u5B57\u7B26\u4E32\u3002 \u4ECE\u5B57\u7B26\u4E32\u5F00\u59CB\u4F4D\u7F6E\uFF08\u4ECE\u5DE6\u5230\u53F3\uFF09\u8FDB\u884C\u67E5\u627E\uFF0C\u627E\u5230\u7B2C\u4E00\u4E2A\u6709\u6548\u7684\u6570\u5B57\u8FDB\u884C\u8F6C\u6362\uFF0C\u5DE6\u53F3\u7A7A\u767D\u5B57\u7B26\u5FFD\u7565\uFF0C\u5982\u679C\u6CA1\u6709\u627E\u5230\uFF0C\u5219\u8FD4\u56DE NaN</p><p><code>parseInt()</code> \u53EF\u4EE5\u4F20\u9012\u7B2C\u4E8C\u4E2A\u53C2\u6570\uFF0C\u8868\u793A\u5C06\u7ED9\u5B9A\u7684\u5B57\u7B26\u4E32\uFF0C\u8BC6\u522B\u4E3A\u591A\u5C11\u8FDB\u5236</p><h3 id="\u5B9E\u4F8B\u6210\u5458" tabindex="-1">\u5B9E\u4F8B\u6210\u5458 <a class="header-anchor" href="#\u5B9E\u4F8B\u6210\u5458" aria-hidden="true">#</a></h3><ul><li><p><code>toFixed() </code></p><p>\u6307\u5B9A\u4FDD\u7559\u5C0F\u6570\u7684\u4F4D\u6570\uFF0C\u4F1A\u56DB\u820D\u4E94\u5165\u3002</p></li><li><p><code>toPrecision()</code></p><p>\u4EE5\u6307\u5B9A\u7684\u7CBE\u5EA6,\u8FD4\u56DE\u4E00\u4E2A\u5B57\u7B26\u4E32\u3002</p></li></ul><h2 id="boolean" tabindex="-1">Boolean <a class="header-anchor" href="#boolean" aria-hidden="true">#</a></h2><p><a href="https://developer.mozilla.org/zh-CN/docs/Web/JavaScript/Reference/Global_Objects/Boolean" target="_blank" rel="noreferrer">MDN</a></p><p><strong>Boolean</strong> \u5BF9\u8C61\u662F\u4E00\u4E2A\u5E03\u5C14\u503C\u7684\u5BF9\u8C61\u5305\u88C5\u5668\u3002</p><p>\u5982\u679C\u9700\u8981\uFF0C\u4F5C\u4E3A\u7B2C\u4E00\u4E2A\u53C2\u6570\u4F20\u9012\u7684\u503C\u5C06\u8F6C\u6362\u4E3A\u5E03\u5C14\u503C\u3002</p><p>\u5982\u679C\u7701\u7565\u6216\u503C <code>0</code>\uFF0C<code>-0</code>\uFF0C<code>null</code>\uFF0C<code>false</code>\uFF0C<code>NaN</code>\uFF0C<code>undefined</code>\uFF0C<code>&quot;&quot;</code>\uFF0C\u8BE5\u5BF9\u8C61\u5177\u6709\u7684\u521D\u59CB\u503C false\u3002</p><p>\u6240\u6709\u5176\u4ED6\u503C\uFF0C\u5305\u62EC\u4EFB\u4F55\u5BF9\u8C61\uFF0C\u7A7A\u6570\u7EC4<code>[]</code>\u6216\u5B57\u7B26\u4E32<code>&quot;false&quot;</code>\uFF0C\u90FD\u4F1A\u521B\u5EFA\u4E00\u4E2A\u521D\u59CB\u503C\u4E3A\u7684\u5BF9\u8C61 true\u3002</p><h2 id="string" tabindex="-1">String <a class="header-anchor" href="#string" aria-hidden="true">#</a></h2><p><a href="https://developer.mozilla.org/zh-CN/docs/Web/JavaScript/Reference/Global_Objects/String" target="_blank" rel="noreferrer">MDN</a></p><h3 id="\u9759\u6001\u6210\u5458-1" tabindex="-1">\u9759\u6001\u6210\u5458 <a class="header-anchor" href="#\u9759\u6001\u6210\u5458-1" aria-hidden="true">#</a></h3><ul><li><code>fromCharCode()</code> \u901A\u8FC7\u4E00\u4E32 Unicode \u521B\u5EFA\u5B57\u7B26\u4E32\u3002</li></ul><h3 id="\u5B9E\u4F8B\u6210\u5458-1" tabindex="-1">\u5B9E\u4F8B\u6210\u5458 <a class="header-anchor" href="#\u5B9E\u4F8B\u6210\u5458-1" aria-hidden="true">#</a></h3><ul><li><code>length</code> \u5C5E\u6027\uFF0C\u8FD4\u56DE\u5B57\u7B26\u4E32\u7684\u957F\u5EA6\u3002</li></ul><p>\u5B57\u7B26\u4E32\u662F\u4E00\u4E2A\u4F2A\u6570\u7EC4\u3002</p><ul><li><p><code>charAt()</code></p><p>\u8FD4\u56DE\u7ED9\u5B9A index\uFF08\u4E0B\u6807\uFF09\u5904\u7684\u5B57\u7B26\uFF1B\u5982\u679C\u6307\u5B9A\u7684 index \u503C\u8D85\u51FA\u4E86\u8BE5\u8303\u56F4\uFF0C\u5219\u8FD4\u56DE\u4E00\u4E2A\u7A7A\u5B57\u7B26\u4E32\u3002</p></li><li><p><code>charCodeAt()</code></p><p>\u8FD4\u56DE\u7ED9\u5B9A index\uFF08\u4E0B\u6807\uFF09\u7684\u5B57\u7B26\u7684 Unicode \u7684\u503C\uFF1B\u5982\u679C index \u8D85\u51FA\u8303\u56F4\uFF0CcharCodeAt() \u8FD4\u56DE NaN\u3002</p></li><li><p><code>concat()</code></p><p>\u5C06\u4E00\u4E2A\u6216\u591A\u4E2A\u5B57\u7B26\u4E32\u4E0E\u539F\u5B57\u7B26\u4E32\u8FDE\u63A5\u5408\u5E76\uFF0C\u5F62\u6210\u4E00\u4E2A\u65B0\u7684\u5B57\u7B26\u4E32\u5E76\u8FD4\u56DE\u3002</p></li><li><p><code>includes()</code></p><p>\u5224\u65AD\u4E00\u4E2A\u5B57\u7B26\u4E32\u91CC\u662F\u5426\u5305\u542B\u5176\u4ED6\u5B57\u7B26\u4E32\u3002</p></li><li><p><code>startWith()</code></p><p>\u5224\u65AD\u5B57\u7B26\u4E32\u7684\u8D77\u59CB\u4F4D\u7F6E\u662F\u5426\u5339\u914D\u5176\u4ED6\u5B57\u7B26\u4E32\u4E2D\u7684\u5B57\u7B26\u3002</p></li><li><p><code>endsWith()</code></p><p>\u5224\u65AD\u4E00\u4E2A\u5B57\u7B26\u4E32\u7684\u662F\u5426\u4EE5\u7ED9\u5B9A\u5B57\u7B26\u4E32\u7ED3\u5C3E\uFF0C\u7ED3\u679C\u8FD4\u56DE\u5E03\u5C14\u503C\u3002</p></li><li><p><code>indexOf()</code></p><p>\u4ECE\u5B57\u7B26\u4E32\u5BF9\u8C61\u4E2D\u8FD4\u56DE\u9996\u4E2A\u88AB\u53D1\u73B0\u7684\u7ED9\u5B9A\u503C\u7684\u7D22\u5F15\u503C\uFF0C\u5982\u679C\u6CA1\u6709\u627E\u5230\u5219\u8FD4\u56DE-1\u3002</p></li><li><p><code>lastInsexOf()</code></p><p>\u4ECE\u5B57\u7B26\u4E32\u5BF9\u8C61\u4E2D\u8FD4\u56DE\u6700\u540E\u4E00\u4E2A\u88AB\u53D1\u73B0\u7684\u7ED9\u5B9A\u503C\u7684\u7D22\u5F15\u503C\uFF0C\u5982\u679C\u6CA1\u6709\u627E\u5230\u5219\u8FD4\u56DE-1\u3002</p></li><li><p><code>padStart()</code></p><p>\u5728\u5F53\u524D\u5B57\u7B26\u4E32\u5934\u90E8\u586B\u5145\u6307\u5B9A\u7684\u5B57\u7B26\u4E32\uFF0C \u76F4\u5230\u8FBE\u5230\u6307\u5B9A\u7684\u957F\u5EA6\u3002 \u8FD4\u56DE\u4E00\u4E2A\u65B0\u7684\u5B57\u7B26\u4E32\u3002</p><blockquote><p>\u8BED\u6CD5\uFF1A<strong>str.padStart(targetLength [, padString])</strong></p></blockquote><p><strong>\u53C2\u6570\uFF1A</strong></p><p>targetLength</p><p>\u5F53\u524D\u5B57\u7B26\u4E32\u9700\u8981\u586B\u5145\u5230\u7684\u76EE\u6807\u957F\u5EA6\u3002\u5982\u679C\u8FD9\u4E2A\u6570\u503C\u5C0F\u4E8E\u5F53\u524D\u5B57\u7B26\u4E32\u7684\u957F\u5EA6\uFF0C\u5219\u8FD4\u56DE\u5F53\u524D\u5B57\u7B26\u4E32\u672C\u8EAB\u3002</p><p>padString \u53EF\u9009</p><p>\u586B\u5145\u5B57\u7B26\u4E32\u3002\u5982\u679C\u5B57\u7B26\u4E32\u592A\u957F\uFF0C\u4F7F\u586B\u5145\u540E\u7684\u5B57\u7B26\u4E32\u957F\u5EA6\u8D85\u8FC7\u4E86\u76EE\u6807\u957F\u5EA6\uFF0C\u5219\u53EA\u4FDD\u7559\u6700\u5DE6\u4FA7\u7684\u90E8\u5206\uFF0C\u5176\u4ED6\u90E8\u5206\u4F1A\u88AB\u622A\u65AD\u3002\u6B64\u53C2\u6570\u7684\u9ED8\u8BA4\u503C\u4E3A &quot; &quot;\uFF08U+0020\uFF09\u3002</p></li><li><p><code>padEnd()</code></p><p>\u5728\u5F53\u524D\u5B57\u7B26\u4E32\u5C3E\u90E8\u586B\u5145\u6307\u5B9A\u7684\u5B57\u7B26\u4E32\uFF0C \u76F4\u5230\u8FBE\u5230\u6307\u5B9A\u7684\u957F\u5EA6\u3002 \u8FD4\u56DE\u4E00\u4E2A\u65B0\u7684\u5B57\u7B26\u4E32\u3002</p></li><li><p><code>repeat()</code></p><p>\u8FD4\u56DE\u6307\u5B9A\u91CD\u590D\u6B21\u6570\u7684\u5B57\u7B26\u4E32</p></li><li><p><code>slice(a,b)</code></p><p>\u6458\u53D6\u4E00\u4E2A\u5B57\u7B26\u4E32\u533A\u57DF\uFF0C\u8FD4\u56DE\u4E00\u4E2A\u65B0\u7684\u5B57\u7B26\u4E32\u3002 \u4ECE a \u4F4D\u7F6E\uFF0C\u53D6\u5230 b \u4F4D\u7F6E\uFF08\u53D6\u4E0D\u5230 b\uFF09\uFF1Ba b \u4F4D\u7F6E\u53EF\u4EE5\u662F\u8D1F\u6570</p></li><li><p><code>substr(a,b)</code></p><p>\u901A\u8FC7\u6307\u5B9A\u5B57\u7B26\u6570\u8FD4\u56DE\u5728\u6307\u5B9A\u4F4D\u7F6E\u5F00\u59CB\u7684\u5B57\u7B26\u4E32\u4E2D\u7684\u5B57\u7B26\u3002 \u4ECE a \u4F4D\u7F6E\uFF0C\u53D6\u6307\u5B9A\u7684\u957F\u5EA6 b \u4E2A\u5B57\u7B26\uFF1Ba b \u4F4D\u7F6E\u53EF\u4EE5\u662F\u8D1F\u6570</p></li><li><p><code>substring()</code></p><p>\u8FD4\u56DE\u5728\u5B57\u7B26\u4E32\u4E2D\u6307\u5B9A\u4E24\u4E2A\u4E0B\u6807\u4E4B\u95F4\u7684\u5B57\u7B26\u3002\u53C2\u6570\u4E0D\u53EF\u662F\u8D1F\u6570\uFF1B\u53C2\u6570\u53EF\u4EE5\u8C03\u6362</p><blockquote><p>\u8BED\u6CD5\uFF1A<strong>str.substring(indexStart[, indexEnd])</strong></p></blockquote><p>substring \u63D0\u53D6\u4ECE indexStart \u5230 indexEnd\uFF08\u4E0D\u5305\u62EC\uFF09\u4E4B\u95F4\u7684\u5B57\u7B26\u3002</p><ul><li>\u5982\u679C indexStart \u7B49\u4E8E indexEnd\uFF0Csubstring \u8FD4\u56DE\u4E00\u4E2A\u7A7A\u5B57\u7B26\u4E32\u3002</li><li>\u5982\u679C\u7701\u7565 indexEnd\uFF0Csubstring \u63D0\u53D6\u5B57\u7B26\u4E00\u76F4\u5230\u5B57\u7B26\u4E32\u672B\u5C3E\u3002</li><li>\u5982\u679C\u4EFB\u4E00\u53C2\u6570\u5C0F\u4E8E 0 \u6216\u4E3A NaN\uFF0C\u5219\u88AB\u5F53\u4F5C 0\u3002</li><li>\u5982\u679C\u4EFB\u4E00\u53C2\u6570\u5927\u4E8E stringName.length\uFF0C\u5219\u88AB\u5F53\u4F5C stringName.length\u3002</li><li>\u5982\u679C indexStart \u5927\u4E8E indexEnd\uFF0C\u5219 substring \u7684\u6267\u884C\u6548\u679C\u5C31\u50CF\u4E24\u4E2A\u53C2\u6570\u8C03\u6362\u4E86\u4E00\u6837\u3002</li></ul></li><li><p><code>toLowerCase()</code></p><p>\u5C06\u5B57\u7B26\u4E32\u8F6C\u6362\u6210\u5C0F\u5199\u5E76\u8FD4\u56DE\u3002</p></li><li><p><code>toUpperCase()</code></p><p>\u5C06\u5B57\u7B26\u4E32\u8F6C\u6362\u6210\u5927\u5199\u5E76\u8FD4\u56DE\u3002</p></li><li><p><code>trim()</code></p><p>\u4ECE\u5B57\u7B26\u4E32\u7684\u5F00\u59CB\u548C\u7ED3\u5C3E\u53BB\u9664\u7A7A\u683C\u3002</p></li><li><p><code>trimStart()</code> \u7B49\u540C\u4E8E <code>trimLeft()</code></p><p>\u4ECE\u5B57\u7B26\u4E32\u7684\u5DE6\u4FA7\u53BB\u9664\u7A7A\u683C\u3002</p></li><li><p><code>trimEnd()</code> \u7B49\u540C\u4E8E <code>trimRight()</code></p><p>\u4ECE\u5B57\u7B26\u4E32\u7684\u53F3\u4FA7\u53BB\u9664\u7A7A\u683C\u3002</p></li><li><p><code>split()</code></p><p>\u4F7F\u7528\u6307\u5B9A\u7684\u5206\u9694\u7B26\u5B57\u7B26\u4E32\u5C06\u4E00\u4E2A String \u5BF9\u8C61\u5206\u5272\u6210\u5B50\u5B57\u7B26\u4E32\u6570\u7EC4\uFF0C\u4EE5\u4E00\u4E2A\u6307\u5B9A\u7684\u5206\u5272\u5B57\u4E32\u6765\u51B3\u5B9A\u6BCF\u4E2A\u62C6\u5206\u7684\u4F4D\u7F6E\u3002</p></li></ul>',24),t=[l];function a(r,c,n,s,h,u){return i(),p("div",null,t)}const _=e(d,[["render",a]]);export{b as __pageData,_ as default};
